145→/* ---------- Flow Card ---------- */
146→
147→function ProjectFlowCard({ project }: { project: Project }) {
148→  const [sourceCreateOpen, setSourceCreateOpen] = useState(false);
149→  const [editingSource, setEditingSource] = useState<Source | null>(null);
150→
151→  const { data: srcData, mutate: mutateSources } = useSWR(
152→    `project-${project.id}-card-sources`,
153→    () => sourcesApi.listByProject(project.id),
154→  );
155→  const { data: relData } = useSWR(
156→    `project-${project.id}-card-releases`,
157→    () => releasesApi.listByProject(project.id, 1, 25),
158→  );
159→  const { data: srData } = useSWR(
160→    `project-${project.id}-card-sr`,
161→    () => srApi.list(project.id, 1, 10),
162→  );
163→
164→  const sources = srcData?.data ?? [];
165→  const releases = relData?.data ?? [];
166→  const srItems = srData?.data ?? [];
167→
168→  const sourceMap = useMemo(() => {
169→    const m = new Map<string, Source>();
170→    for (const s of sources) m.set(s.id, s);
171→    return m;
172→  }, [sources]);
173→
174→  return (
175→    <div
176→      className="rounded-md px-5 py-4"
177→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
178→    >
179→      {/* Header */}
180→      <div className="flex items-center justify-between mb-2">
181→        <div className="flex items-center gap-3 min-w-0">
182→          <ProjectCardLogo projectId={project.id} name={project.name} />
183→          <div className="min-w-0">
184→            <Link
185→              href={`/projects/${project.id}`}
186→              className="group inline-flex items-center gap-1.5 text-[16px] font-bold transition-colors"
187→              style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a" }}
188→            >
189→              {project.name}
190→              <ArrowRight className="h-3.5 w-3.5 opacity-0 -translate-x-1 transition-all group-hover:opacity-100 group-hover:translate-x-0" />
191→            </Link>
192→            {project.description && (
193→              <p
194→                className="text-[13px] truncate"
195→                style={{ color: "#6b7280", fontFamily: "var(--font-dm-sans)" }}
196→              >
197→                {project.description}
198→              </p>
199→            )}
200→          </div>
201→        </div>
202→      </div>
203→
204→      {/* Sources chips */}
205→      <div className="flex flex-wrap items-center gap-1.5 mb-3">
206→        <span
207→          className="text-[11px] font-medium uppercase tracking-[0.08em] mr-0.5"
208→          style={{ color: "#9ca3af", fontFamily: "var(--font-dm-sans)" }}
209→        >
210→          Sources:
211→        </span>
212→        {sources.map((source) => (
213→          <button
214→            key={source.id}
215→            onClick={() => setEditingSource(source)}
216→            className="group/chip inline-flex items-center gap-1.5 rounded px-2 py-0.5 text-[12px] transition-colors hover:bg-[#f0f0ee]"
217→            style={{
218→              backgroundColor: "#fafaf9",
219→              border: "1px solid #e8e8e5",
220→            }}
221→          >
222→            <span
223→              className="inline-block h-1.5 w-1.5 rounded-full shrink-0"
224→              style={{ backgroundColor: source.enabled ? "#16a34a" : "#d1d5db" }}
225→            />
226→            {(() => { const Icon = getProviderIcon(source.provider); return Icon ? <Icon size={12} className="shrink-0" style={{ color: "#9ca3af" }} /> : null; })()}
227→            <span style={{ fontFamily: "'JetBrains Mono', monospace", color: "#374151" }}>
228→              {source.repository}
229→            </span>
230→            {source.last_polled_at && (
231→              <span style={{ color: "#9ca3af" }}>
232→                {timeAgo(source.last_polled_at).replace(" ago", "")}
233→              </span>
234→            )}
235→            <Pencil className="h-2.5 w-2.5 hidden group-hover/chip:inline shrink-0" style={{ color: "#9ca3af", opacity: 0.5 }} />
236→          </button>
237→        ))}
238→        <button
239→          onClick={() => setSourceCreateOpen(true)}
240→          className="inline-flex items-center gap-1 px-2 py-0.5 text-[12px] font-medium rounded border transition-colors hover:bg-[#f3f3f1]"
241→          style={{
242→            borderColor: "#e8e8e5",
243→            color: "#9ca3af",
244→            fontFamily: "var(--font-dm-sans)",
245→          }}
246→        >
247→          <Plus className="h-3 w-3" />
248→          Add Source
249→        </button>
250→      </div>
251→
252→      {/* Releases flow */}
253→      {releases.length > 0 && (
254→        <FlowSection label="Releases" moreHref={`/releases?project=${project.id}`}>
255→          {releases.map((r) => {
256→            const src = sourceMap.get(r.source_id);
257→            return (
258→              <span key={r.id} className="inline-flex items-baseline mr-2.5">
259→                <Link
260→                  href={`/releases/${r.id}`}
261→                  className="text-[#2563eb] hover:underline"
262→                  style={{ fontFamily: "'JetBrains Mono', monospace", fontSize: "12px" }}
263→                >
264→                  {r.version}
265→                </Link>
266→                {src && (
267→                  <span
268→                    className="text-[11px] ml-1 hidden sm:inline"
269→                    style={{ color: "#9ca3af" }}
270→                  >
271→                    ({src.repository.split("/").pop()})
272→                  </span>
273→                )}
274→                <span
275→                  className="text-[11px] ml-1"
276→                  style={{ color: "#c4c4c0" }}
277→                >
278→                  {timeAgo(r.released_at || r.created_at).replace(" ago", "")}
279→                </span>
280→              </span>
281→            );
282→          })}
283→        </FlowSection>
284→      )}
285→
286→      {/* Semantic releases */}
287→      {srItems.length > 0 && (
288→        <FlowSection label="Semantic Releases" moreHref={`/semantic-releases?project=${project.id}`}>
289→          {srItems.map((sr) => {
290→            const urgencyStyle = sr.report?.urgency
291→              ? URGENCY_COLORS[sr.report.urgency.toLowerCase()]
292→              : undefined;
293→            return (
294→              <span key={sr.id} className="inline-flex items-center gap-1.5 mr-2.5">
295→                <Link
296→                  href={`/projects/${project.id}/semantic-releases/${sr.id}`}
297→                  className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-blue-300 transition-shadow"
298→                  style={{
299→                    backgroundColor: "#eff6ff",
300→                    fontFamily: "'JetBrains Mono', monospace",
301→                    color: "#1d4ed8",
302→                  }}
303→                >
304→                  {sr.version}
305→                </Link>
306→                {urgencyStyle && (
307→                  <span
308→                    className="rounded px-1.5 py-0.5 text-[10px] uppercase font-bold tracking-wide leading-none"
309→                    style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
310→                  >
311→                    {sr.report?.urgency}
312→                  </span>
313→                )}
314→              </span>
315→            );
316→          })}
317→        </FlowSection>
318→      )}
319→
320→      {/* Add Source dialog */}
321→      <Dialog open={sourceCreateOpen} onOpenChange={setSourceCreateOpen}>
322→        <DialogContent className="sm:max-w-lg">
323→          <DialogHeader>
324→            <DialogTitle>Add Source</DialogTitle>
325→          </DialogHeader>
326→          <SourceForm
327→            title="Add Source"
328→            projectId={project.id}
329→            onSubmit={async (input) => {
330→              const res = await sourcesApi.create(project.id, input);
331→              if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
332→            }}
333→            onSuccess={() => {
334→              setSourceCreateOpen(false);
335→              mutateSources();
336→            }}
337→            onCancel={() => setSourceCreateOpen(false)}
338→          />
339→        </DialogContent>
340→      </Dialog>
341→
342→      {/* Edit Source dialog */}
343→      <Dialog
344→        open={!!editingSource}
345→        onOpenChange={(open) => { if (!open) setEditingSource(null); }}
346→      >
347→        <DialogContent className="sm:max-w-lg">
348→          <DialogHeader>
349→            <DialogTitle>Edit Source</DialogTitle>
350→          </DialogHeader>
351→          {editingSource && (
352→            <SourceForm
353→              key={editingSource.id}
354→              title="Edit Source"
355→              initial={editingSource}
356→              onSubmit={async (input) => {
357→                await sourcesApi.update(editingSource.id, input);
358→              }}
359→              onSuccess={() => {
360→                setEditingSource(null);
361→                mutateSources();
362→              }}
363→              onCancel={() => setEditingSource(null)}
364→            />
365→          )}
366→        </DialogContent>
367→      </Dialog>
368→    </div>
369→  );
370→}
