372→/* ---------- Compact Row ---------- */
373→
374→function ProjectCompactRow({ project }: { project: Project }) {
375→  const router = useRouter();
376→  const { data: relData } = useSWR(`project-${project.id}-card-releases`, () =>
377→    releasesApi.listByProject(project.id, 1, 5)
378→  );
379→  const { data: srcData } = useSWR(`project-${project.id}-card-sources`, () =>
380→    sourcesApi.listByProject(project.id)
381→  );
382→  const { data: srData } = useSWR(`project-${project.id}-card-sr`, () =>
383→    srApi.list(project.id, 1, 3)
384→  );
385→
386→  const releases = relData?.data ?? [];
387→  const sources = srcData?.data ?? [];
388→  const srItems = srData?.data ?? [];
389→  const latest = releases[0];
390→  const latestSr = srItems[0];
391→
392→  const sourceMap = useMemo(() => {
393→    const m = new Map<string, Source>();
394→    for (const s of sources) m.set(s.id, s);
395→    return m;
396→  }, [sources]);
397→
398→  const latestSrc = latest ? sourceMap.get(latest.source_id) : undefined;
399→  const latestIcon = latestSrc ? getProviderIcon(latestSrc.provider) : undefined;
400→
401→  const urgencyStyle = latestSr?.report?.urgency
402→    ? URGENCY_COLORS[latestSr.report.urgency.toLowerCase()]
403→    : undefined;
404→
405→  return (
406→    <div
407→      onClick={() => router.push(`/projects/${project.id}`)}
408→      className="flex items-center gap-4 rounded-md px-4 py-2.5 transition-colors hover:bg-[#f9f9f7] cursor-pointer"
409→      style={{ border: "1px solid #e8e8e5", backgroundColor: "#ffffff" }}
410→    >
411→      {/* Project name */}
412→      <span
413→        className="flex items-center gap-2 text-[14px] font-bold shrink-0"
414→        style={{ fontFamily: "var(--font-fraunces)", color: "#e8601a", minWidth: "160px" }}
415→      >
416→        <ProjectLogo name={project.name} sources={sources} size={24} />
417→        {project.name}
418→      </span>
419→
420→      {/* Latest release */}
421→      <span className="flex items-center gap-1.5 shrink-0" style={{ minWidth: "140px" }}>
422→        {latest ? (
423→          <>
424→            <Link
425→              href={`/releases/${latest.id}`}
426→              onClick={(e) => e.stopPropagation()}
427→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none hover:ring-1 hover:ring-gray-300 transition-shadow"
428→              style={{
429→                backgroundColor: "#f3f3f1",
430→                fontFamily: "'JetBrains Mono', monospace",
431→                color: "#374151",
432→              }}
433→            >
434→              {latest.version}
435→            </Link>
436→            {latestIcon && latestIcon({ size: 12, className: "shrink-0", style: { color: "#9ca3af" } })}
437→          </>
438→        ) : (
439→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
440→            No releases
441→          </span>
442→        )}
443→      </span>
444→
445→      {/* Latest semantic release */}
446→      <span className="flex items-center gap-1.5 flex-1 min-w-0">
447→        {latestSr ? (
448→          <>
449→            <Link
450→              href={`/projects/${project.id}/semantic-releases/${latestSr.id}`}
451→              onClick={(e) => e.stopPropagation()}
452→              className="inline-flex items-center rounded px-1.5 py-0.5 text-[12px] leading-none shrink-0 hover:ring-1 hover:ring-blue-300 transition-shadow"
453→              style={{
454→                backgroundColor: "#eff6ff",
455→                fontFamily: "'JetBrains Mono', monospace",
456→                color: "#1d4ed8",
457→              }}
458→            >
459→              {latestSr.version}
460→            </Link>
461→            {urgencyStyle && (
462→              <span
463→                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
464→                style={{ backgroundColor: urgencyStyle.bg, color: urgencyStyle.text }}
465→              >
466→                {latestSr.report?.urgency}
467→              </span>
468→            )}
469→            {latestSr.report?.summary && (
470→              <span className="text-[11px] truncate" style={{ color: "#9ca3af" }}>
471→                {latestSr.report.summary.length > 60
472→                  ? latestSr.report.summary.slice(0, 60) + "\u2026"
473→                  : latestSr.report.summary}
474→              </span>
475→            )}
476→          </>
477→        ) : (
478→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
479→            No analysis
480→          </span>
481→        )}
482→      </span>
483→
484→      {/* Arrow */}
485→      <ArrowRight className="h-3.5 w-3.5 shrink-0" style={{ color: "#c4c4c0" }} />
486→    </div>
487→  );
488→}
