490→/* ---------- Page ---------- */
491→
492→export default function ProjectsPage() {
493→  const [createOpen, setCreateOpen] = useState(false);
494→  const [viewMode, setViewMode] = useState<"cards" | "compact">("cards");
495→  const [search, setSearch] = useState("");
496→  const [page, setPage] = useState(1);
497→  const { data, isLoading } = useSWR("projects", () => projectsApi.list(1, 100));
498→  const items = data?.data ?? [];
499→
500→  const PAGE_SIZE = 12;
501→  const filtered = search
502→    ? items.filter((p) => p.name.toLowerCase().includes(search.toLowerCase()))
503→    : items;
504→  const totalPages = Math.max(1, Math.ceil(filtered.length / PAGE_SIZE));
505→  const currentPage = Math.min(page, totalPages);
506→  const paged = filtered.slice((currentPage - 1) * PAGE_SIZE, currentPage * PAGE_SIZE);
507→
508→  return (
509→    <div className="flex flex-col gap-4 fade-in">
510→      <div className="flex items-center justify-between">
511→        <div>
512→          <h1
513→            style={{
514→              fontFamily: "var(--font-fraunces)",
515→              fontSize: "24px",
516→              fontWeight: 700,
517→              color: "#111113",
518→            }}
519→          >
520→            Projects
521→          </h1>
522→          <p
523→            className="mt-1 text-[13px] text-[#6b7280]"
524→            style={{ fontFamily: "var(--font-dm-sans)" }}
525→          >
526→            Tracked software projects and their recent releases.
527→          </p>
528→        </div>
529→        <div className="flex items-center gap-2">
530→          <div className="relative">
531→            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 h-3.5 w-3.5" style={{ color: "#9ca3af" }} />
532→            <input
533→              type="text"
534→              value={search}
535→              onChange={(e) => { setSearch(e.target.value); setPage(1); }}
536→              placeholder="Search projects..."
537→              className="rounded-md border py-1.5 pl-8 pr-3 text-[13px] w-48"
538→              style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)", color: "#374151" }}
539→            />
540→          </div>
541→          <div className="flex items-center rounded-md border" style={{ borderColor: "#e8e8e5" }}>
542→            <button
543→              onClick={() => setViewMode("cards")}
544→              className="p-1.5 rounded-l-md transition-colors"
545→              style={{
546→                backgroundColor: viewMode === "cards" ? "#f3f3f1" : "transparent",
547→                color: viewMode === "cards" ? "#111113" : "#9ca3af",
548→              }}
549→              title="Card view"
550→            >
551→              <LayoutGrid className="h-4 w-4" />
552→            </button>
553→            <button
554→              onClick={() => setViewMode("compact")}
555→              className="p-1.5 rounded-r-md transition-colors"
556→              style={{
557→                backgroundColor: viewMode === "compact" ? "#f3f3f1" : "transparent",
558→                color: viewMode === "compact" ? "#111113" : "#9ca3af",
559→              }}
560→              title="Compact view"
561→            >
562→              <List className="h-4 w-4" />
563→            </button>
564→          </div>
565→          <button
566→            onClick={() => setCreateOpen(true)}
567→            className="flex items-center gap-1.5 rounded px-3 py-1.5 text-[13px] text-white transition-opacity hover:opacity-90"
568→            style={{ backgroundColor: "#e8601a", fontFamily: "var(--font-dm-sans)" }}
569→          >
570→            <Plus className="h-3.5 w-3.5" />
571→            New Project
572→          </button>
573→        </div>
574→      </div>
575→
576→      {isLoading ? (
577→        <p
578→          className="px-4 py-8 text-center text-[14px] italic text-[#9ca3af]"
579→          style={{ fontFamily: "var(--font-fraunces)" }}
580→        >
